using System;
using System.Collections.Generic;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.WriteLine("Asinxron axın başlayır...");
        await foreach (var number in GenerateNumbersAsync())
        {
            Console.WriteLine($"Alınan ədəd: {number}");
        }
        Console.WriteLine("Axın bitdi.");
    }

    static async IAsyncEnumerable<int> GenerateNumbersAsync()
    {
        for (int i = 1; i <= 5; i++)
        {
            await Task.Delay(500); // 0.5 saniyəlik gecikmə
            yield return i;
        }
    }
}
// Output:
// Asinxron axın başlayır...
// Alınan ədəd: 1
// Alınan ədəd: 2
// Alınan ədəd: 3
// Alınan ədəd: 4
// Alınan ədəd: 5
// Axın bitdi.

using System;
using System.Collections.Generic;
using System.Threading;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        using var cts = new CancellationTokenSource(1500); // 1.5 saniyədən sonra ləğv et
        Console.WriteLine("Asinxron axın başlayır...");
        try
        {
            await foreach (var number in GenerateNumbersAsync(cts.Token))
            {
                Console.WriteLine($"Alınan ədəd: {number}");
            }
        }
        catch (OperationCanceledException)
        {
            Console.WriteLine("Axın ləğv edildi!");
        }
    }

    static async IAsyncEnumerable<int> GenerateNumbersAsync(CancellationToken token)
    {
        for (int i = 1; i <= 10; i++)
        {
            token.ThrowIfCancellationRequested();
            await Task.Delay(500, token); // 0.5 saniyəlik gecikmə
            yield return i;
        }
    }
}
// Output:
// Asinxron axın başlayır...
// Alınan ədəd: 1
// Alınan ədəd: 2
// Alınan ədəd: 3
// Axın ləğv edildi!

using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
