using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.WriteLine("Paralel tapşırıqlar başlayır...");
        var sources = new[] { GenerateNumbersAsync(1), GenerateNumbersAsync(2) };
        var merged = MergeStreams(sources);
        await foreach (var number in merged)
        {
            Console.WriteLine($"Alınan ədəd: {number}");
        }
        Console.WriteLine("Paralel tapşırıqlar bitdi.");
    }

    static async IAsyncEnumerable<int> GenerateNumbersAsync(int sourceId)
    {
        for (int i = 1; i <= 3; i++)
        {
            await Task.Delay(500);
            yield return i * 10 + sourceId;
        }
    }

    static async IAsyncEnumerable<int> MergeStreams(IEnumerable<IAsyncEnumerable<int>> streams)
    {
        var tasks = streams.Select(async stream =>
        {
            var results = new List<int>();
            await foreach (var item in stream)
            {
                results.Add(item);
            }
            return results;
        }).ToList();

        var results = await Task.WhenAll(tasks);
        foreach (var result in results.SelectMany(x => x))
        {
            yield return result;
        }
    }
}
// Output (mümkün ardıcıllıq):
// Paralel tapşırıqlar başlayır...
// Alınan ədəd: 11
// Alınan ədəd: 21
// Alınan ədəd: 12
// Alınan ədəd: 22
// Alınan ədəd: 13
// Alınan ədəd: 23
// Paralel tapşırıqlar bitdi.

